def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority_score = 0.0
        if ratio > 2:
            priority_score += ratio ** 4
            for k in range(1, int(np.ceil(ratio)) + 1):
                priority_score -= (np.exp(-k * ratio) / (k ** 2))
        elif 1 < ratio <= 2:
            priority_score += np.log(ratio + 1) * 5
            for m in range(int(capacity)):
                priority_score += ((-1) ** m) * (ratio ** (m + 1)) / (m + 1)
        elif 0.25 < ratio <= 1:
            priority_score += -np.log(1 - ratio + 1e-10) * 3
            for n in range(1, int(capacity) + 1):
                priority_score += (np.sin(n * ratio) / (n + 0.5))
            if capacity % 2 == 0:
                priority_score *= 1.1
            else:
                priority_score *= 0.9
        else:
            harmonic_sum = 0
            for j in range(1, max(2, int(capacity)) + 1):
                harmonic_sum += 1 / j
            exponential_sum = 0
            for p in range(1, int(capacity) + 1):
                exponential_sum += (ratio ** p) / (p ** 0.5)
            priority_score += harmonic_sum + exponential_sum
            if priority_score == 0:
                priority_score = 1.5
        if capacity < item:
            penalty = (item - capacity) * 15
            for q in range(3):
                penalty += (q + 1) * (item - capacity) ** (q + 1) * 0.5
            priority_score += penalty
        priorities[i] = priority_score
    return priorities
